// frontend/src/components/Forecast.jsx
import React from "react";

export default function Forecast({ hourly = [], daily = [], daily16 = [] }) {
  return (
    <div className="grid gap-4">
      {/* Hourly */}
      <section className="rounded-2xl bg-black/30 backdrop-blur-md text-white p-4">
        <div className="font-semibold mb-2">Hourly (next 48h)</div>
        <div className="grid grid-cols-2 sm:grid-cols-4 md:grid-cols-6 gap-3">
          {hourly.slice(0, 12).map((h, i) => (
            <div key={i} className="rounded-xl bg-white/10 p-3 text-sm">
              <div>{new Date((h.date || 0) * 1000).toLocaleTimeString([], { hour: "numeric" })}</div>
              <div className="text-xl font-bold">{h?.temp != null ? Math.round(h.temp) : "--"}°</div>
              <div className="opacity-80">{h?.weather || "—"}</div>
            </div>
          ))}
        </div>
      </section>

      {/* Daily (7–10d from OneCall) */}
      <section className="rounded-2xl bg-black/30 backdrop-blur-md text-white p-4">
        <div className="font-semibold mb-2">Daily</div>
        <div className="grid gap-2">
          {daily.slice(0, 10).map((d, i) => (
            <div key={i} className="flex items-center justify-between rounded-xl bg-white/10 p-3 text-sm">
              <div>{new Date((d.date || 0) * 1000).toLocaleDateString([], { weekday: "short" })}</div>
              <div className="opacity-80">{d?.weather || "—"}</div>
              <div className="font-bold">
                {d?.temp?.max != null ? Math.round(d.temp.max) : "--"}° / {d?.temp?.min != null ? Math.round(d.temp.min) : "--"}°
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* 16‑day (legacy endpoint) */}
      {daily16?.length > 0 && (
        <section className="rounded-2xl bg-black/30 backdrop-blur-md text-white p-4">
          <div className="font-semibold mb-2">Extended (16‑day)</div>
          <div className="grid gap-2">
            {daily16.map((d, i) => (
              <div key={i} className="flex items-center justify-between rounded-xl bg-white/10 p-3 text-sm">
                <div>{new Date((d.date || 0) * 1000).toLocaleDateString([], { weekday: "short" })}</div>
                <div className="opacity-80">{d?.weather || "—"}</div>
                <div className="font-bold">
                  {d?.temp?.max != null ? Math.round(d.temp.max) : "--"}° / {d?.temp?.min != null ? Math.round(d.temp.min) : "--"}°
                </div>
              </div>
            ))}
          </div>
        </section>
      )}
    </div>
  );
}
